import java.util.List;
public class Main {
    public static void main(String[] args) {
        Member.resetCounter();
        Library lib = new Library("Test");
        lib.addBook("ISBN-A", "Java Concurrency", "Goetz", 2006, 1);
        lib.addBook("ISBN-B", "Effective Java", "Bloch", 2018, 1);
        lib.addBook("ISBN-C", "Clean Code", "Martin", 2008, 1);
        lib.setSearchStrategy(new TitleSearch());
        List<Book> r1 = lib.search("Java");
        System.out.println("TITLE_HITS_" + r1.size());
        lib.setSearchStrategy(new AuthorSearch());
        List<Book> r2 = lib.search("Bloch");
        System.out.println("AUTHOR_HITS_" + r2.size());
        lib.setSearchStrategy(new ISBNSearch());
        List<Book> r3 = lib.search("ISBN-C");
        System.out.println("ISBN_HITS_" + r3.size());
    }
}

/* Test driver */
import java.time.LocalDate;
public class Main {
    public static void main(String[] args) {
        Member.resetCounter();
        Library lib = new Library("Test");
        Book b = lib.addBook("ISBN-X", "BookX", "Auth", 2020, 1);
        Member alice = lib.registerMember("Alice");
        Member bob = lib.registerMember("Bob");
        LocalDate d = LocalDate.of(2026, 1, 1);
        BorrowRecord r = lib.borrowBook(alice, b, d);
        Reservation res = lib.reserveBook(bob, b, d);
        if (res == null) { System.out.println("FAIL_RES"); System.exit(1); }
        System.out.println("RESERVED_OK");
        System.out.println("FULFILLED_BEFORE_" + res.isFulfilled());
        lib.returnBook(r, d.plusDays(3));
        System.out.println("FULFILLED_AFTER_" + res.isFulfilled());
    }
}
